#!/usr/bin/env node
/**
 * shard-story-bundle — one self-contained story file per implementation task.
 *
 * Closes research gap #5 (docs/research/2026-06-24_github-enrichment-research.md):
 * the planning→coding handoff lost context. dispatch-parallel-implementations copies
 * the raw master spec and get-spec-context emits a table of contents (pointers), so
 * the implementer subagent must re-derive ancestry N times — and agent definitions
 * never even instruct it to call get-spec-context. The ancestry meaning lives UP the
 * chain (CLAUDE.md "Read the Spec Hierarchy"), so pointers lose exactly what matters.
 *
 * This flattens the controlling spec + its full L0→Ln ancestry content (inlined, not
 * linked) + the acceptance criteria into a single docs/specs/stories/<wave>-<task>.story.md.
 * Retrieval happens ONCE at packaging time and lands on disk where the existing gates
 * already cover it; the implementer reads one file and does retrieval zero times.
 *
 * Idea from BMAD-METHOD story sharding — a script, no 12-persona scaffold.
 *
 * Usage:
 *   node scripts/shard-story-bundle.mjs --feature <name> --wave <id> --task <slug>
 *   node scripts/shard-story-bundle.mjs --spec docs/specs/wave-x_MASTER_SPEC.md --wave x --task build
 *   node scripts/shard-story-bundle.mjs --self-test
 */

import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { execSync } from 'node:child_process';
import { dirname, resolve, basename } from 'node:path';
import { fileURLToPath, pathToFileURL } from 'node:url';

const ROOT = resolve(dirname(fileURLToPath(import.meta.url)), '..');
const slug = (f) => String(f).toLowerCase().replace(/[^a-z0-9.-]+/g, '-').replace(/^-+|-+$/g, '');

export function featureFromSpec(specPath) {
  return slug(basename(specPath).replace(/\.md$/i, '').replace(/_?master_?spec$/i, '').replace(/[_-]+$/g, ''));
}

/** Pull acceptance criteria from spec text: AC-id lines, or bullets under an Acceptance heading. */
export function extractACs(text) {
  const lines = String(text).split('\n');
  const acs = [];
  let inAc = false;
  for (const line of lines) {
    if (/^#{1,6}\s/.test(line)) inAc = /acceptance|acceptance criteria|критери/i.test(line);
    const idHit = /\bAC[-\s]?\d+/i.test(line);
    const bulletInSection = inAc && /^\s*([-*]|\d+[.)])\s+\S/.test(line);
    if (idHit || bulletInSection) acs.push(line.trim().replace(/^([-*]|\d+[.)])\s+/, ''));
  }
  return [...new Set(acs)];
}

export function buildStory({ wave, task, matched, ancestry = [], acs = [] }) {
  const out = [];
  out.push(`# Story bundle — ${wave} · ${task}`);
  out.push('');
  out.push('> Self-contained. Everything the implementer needs is inlined below — do NOT re-derive');
  out.push('> ancestry; read this file top to bottom. Generated by shard-story-bundle.mjs.');
  out.push('');
  if (acs.length) {
    out.push('## Acceptance criteria (must all hold)');
    out.push('');
    for (const a of acs) out.push(`- [ ] ${a}`);
    out.push('');
  }
  out.push(`## Controlling spec — ${matched.title || matched.path} ${matched.level ? `[${matched.level}]` : ''}`);
  out.push(`<!-- source: ${matched.path} -->`);
  out.push('');
  out.push(matched.text || '_(spec body unavailable)_');
  out.push('');
  if (ancestry.length) {
    out.push('## Ancestry (inlined, top of the chain first)');
    out.push('');
    for (const a of ancestry) {
      out.push(`### ${a.title || a.path} ${a.level ? `[${a.level}]` : ''}`);
      out.push(`<!-- source: ${a.path} -->`);
      out.push('');
      out.push(a.text || '_(unavailable)_');
      out.push('');
    }
  }
  return out.join('\n');
}

function readSpecText(relPath) {
  const abs = resolve(ROOT, relPath);
  try { return readFileSync(abs, 'utf8'); } catch { return ''; }
}

function resolveContext(feature) {
  try {
    const json = execSync(`node ${resolve(ROOT, 'scripts/get-spec-context.mjs')} --feature ${JSON.stringify(feature)} --format json`, { cwd: ROOT, encoding: 'utf8', stdio: ['ignore', 'pipe', 'ignore'] });
    return JSON.parse(json);
  } catch { return { matched: null, ancestry: [] }; }
}

function arg(args, name) { const i = args.indexOf(name); return i >= 0 ? args[i + 1] : undefined; }

function main() {
  const args = process.argv.slice(2);
  if (args.includes('--self-test')) return selfTest();

  const specPath = arg(args, '--spec');
  const feature = arg(args, '--feature') || (specPath ? featureFromSpec(specPath) : null);
  const wave = arg(args, '--wave') || feature || 'wave';
  const task = slug(arg(args, '--task') || 'build');
  if (!feature) { console.error('shard-story-bundle: --feature <name> or --spec <path> required'); process.exit(2); }

  const ctx = resolveContext(feature);
  let matched = ctx.matched;
  if (!matched && specPath) matched = { path: specPath, title: basename(specPath), level: null };
  if (!matched) { console.error(`shard-story-bundle: no controlling spec for "${feature}"`); process.exit(1); }

  matched.text = readSpecText(matched.path);
  const ancestry = (ctx.ancestry || []).map((a) => ({ ...a, text: readSpecText(a.path) }));
  const acs = extractACs(matched.text);

  const story = buildStory({ wave, task, matched, ancestry, acs });
  const outDir = arg(args, '--out') || 'docs/specs/stories';
  const outPath = `${outDir}/${slug(wave)}-${task}.story.md`;
  if (args.includes('--print')) { process.stdout.write(story + '\n'); return; }
  mkdirSync(resolve(ROOT, outDir), { recursive: true });
  writeFileSync(resolve(ROOT, outPath), story);
  console.log(`shard-story-bundle: wrote ${outPath} (spec + ${ancestry.length} ancestor(s) + ${acs.length} AC) inlined`);
}

function selfTest() {
  let fail = 0;
  const ok = (c, m) => { if (c) console.log(`  ✓ ${m}`); else { console.error(`  ✗ ${m}`); fail++; } };
  console.log('shard-story-bundle --self-test');

  ok(featureFromSpec('docs/specs/wave-foo_MASTER_SPEC.md') === 'wave-foo', 'feature derived from spec path');

  const specText = [
    '# Wave Foo', '## Acceptance Criteria', '- the page loads under 1s', '- empty state shows a hint',
    'Some prose.', 'AC-3: error toast on failure',
  ].join('\n');
  const acs = extractACs(specText);
  ok(acs.includes('the page loads under 1s'), 'extracts bullets under an Acceptance heading');
  ok(acs.some((a) => /AC-3/.test(a)), 'extracts AC-id lines anywhere');
  ok(extractACs('# Title\njust prose, no ac').length === 0, 'no false ACs on plain prose');

  const story = buildStory({
    wave: 'wave-foo', task: 'build',
    matched: { path: 'docs/specs/wave-foo_MASTER_SPEC.md', title: 'Wave Foo', level: 'L3', text: 'CONTROLLING-BODY' },
    ancestry: [{ path: 'docs/MISSION.md', title: 'Mission', level: 'L0', text: 'ANCESTOR-BODY' }],
    acs: ['the page loads under 1s'],
  });
  ok(story.includes('CONTROLLING-BODY'), 'inlines the controlling spec body');
  ok(story.includes('ANCESTOR-BODY'), 'inlines the ancestry body (not just a pointer)');
  ok(story.includes('- [ ] the page loads under 1s'), 'renders ACs as a checklist');
  ok(story.includes('Self-contained'), 'tells the implementer not to re-derive');

  console.log(fail === 0 ? '\nshard-story-bundle: all self-tests passed' : `\nshard-story-bundle: ${fail} self-test(s) FAILED`);
  process.exit(fail === 0 ? 0 : 1);
}

if (import.meta.url === pathToFileURL(process.argv[1] || '').href) main();
